def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = ratio ** 4 + (capacity % 3) * 0.5
        elif 1 < ratio <= 2:
            priorities[i] = ratio ** 3 - np.sqrt(capacity)
        elif ratio == 1:
            priorities[i] = 0
        else:
            log_ratio = np.log(ratio)
            if log_ratio < -2:
                priorities[i] = (-log_ratio) * 3 + (capacity % 5) * 0.3
            elif -2 <= log_ratio < -1:
                priorities[i] = (-log_ratio) * 2.5
            else:
                priorities[i] = -log_ratio * 1.2
        if capacity < item * 1.2:
            priorities[i] *= 2
            for j in range(i):
                if bins[j] > capacity:
                    priorities[i] += 0.1 * (bins[j] - capacity)
        elif capacity > item * 2:
            priorities[i] *= 0.5
            for k in range(i + 1, len(bins)):
                if bins[k] < capacity:
                    priorities[i] -= 0.05 * (capacity - bins[k])
        else:
            priorities[i] *= 1
        if priorities[i] < 0:
            priorities[i] = abs(priorities[i]) * 0.8
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if not np.isfinite(priorities[i]):
                priorities[i] = max_priority * 10
            elif priorities[i] > max_priority:
                priorities[i] = max_priority
            elif priorities[i] < min_priority:
                priorities[i] = min_priority
    else:
        priorities[:] = 1e6
    return priorities
